function autoFormatTime(C){let F=C['value']['replace'](/\D/g,'');switch(F['length']>0x4&&(F=F['slice'](0x0,0x4)),F['length']){case 0x0:case 0x1:case 0x2:C['value']=F;break;case 0x3:if(parseInt(F['slice'](0x0,0x2),0xa)<=0x17)C['value']=F['slice'](0x0,0x2)+':'+F['slice'](0x2);else{let d=F['slice'](0x0,0x1)['padStart'](0x2,'0'),T=F['slice'](0x1);C['value']=d+':'+T;}break;case 0x4:let w=F['slice'](0x0,0x2),P=F['slice'](0x2);C['value']=w+':'+P;}}function transformTimeValue(C){let F=C['trim']();if(/^\d{2}$/['test'](F))return F[0x0]['padStart'](0x2,'0')+':'+F[0x1]['padStart'](0x2,'0');if(/^\d{3,4}$/['test'](F))return 0x3===F['length']?parseInt(F['slice'](0x0,0x2),0xa)<=0x17?F['slice'](0x0,0x2)+':'+F['slice'](0x2):F['slice'](0x0,0x1)['padStart'](0x2,'0')+':'+F['slice'](0x1):F['slice'](0x0,0x2)+':'+F['slice'](0x2);if(F['includes'](':')){let [w,P]=F['split'](':');return P||(P='00'),w=w['padStart'](0x2,'0'),P=P['padStart'](0x2,'0'),w+':'+P;}return F;}